@media (max-width: 992px) {
    .dashboard-header {
        flex-direction: column;
        align-items: stretch;
        padding: 20px;
    }

    .search-container {
        max-width: 100%;
    }

    .unit-toggle-container {
        justify-content: center;
    }

    .city-name {
        font-size: 2rem;
    }

    .current-temp {
        font-size: 3.5rem;
    }

    .weather-description {
        font-size: 1.1rem;
    }

    .weather-details {
        grid-template-columns: 1fr;
    }
}

